@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application

<div class="step-indicator d-flex justify-content-between mb-4 position-relative">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var status = GetStepStatus(stepIndex);
        <div class="step-item text-center flex-fill @status"
             @onclick="() => OnStepClick(stepIndex)"
             role="button">
            <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center
                        rounded-circle @GetCircleClass(status)">
                @if (status == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <small class="@GetLabelClass(status)">@StepNames[stepIndex]</small>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public int HighestCompletedStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigateToStep { get; set; }

    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (step < HighestCompletedStep) return "completed";
        return "future";
    }

    private string GetCircleClass(string status) => status switch
    {
        "active" => "bg-primary text-white",
        "completed" => "bg-success text-white",
        _ => "bg-secondary text-white opacity-50"
    };

    private string GetLabelClass(string status) => status switch
    {
        "active" => "fw-bold text-primary",
        "completed" => "text-success",
        _ => "text-muted"
    };

    private async Task OnStepClick(int step)
    {
        if (step < HighestCompletedStep)
        {
            await OnNavigateToStep.InvokeAsync(step);
        }
    }
}

@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application

<style>
    .step-circle {
        width: 36px;
        height: 36px;
        font-size: 0.9rem;
    }
    .step-item.completed {
        cursor: pointer;
    }
    .step-item.future {
        cursor: default;
    }
</style>

