@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" @bind="FullName" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
           @bind="Email" @bind:event="oninput" />
    @if (EmailError is not null)
    {
        <div class="invalid-feedback">@EmailError</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Phone" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Address" @bind:event="oninput"></textarea>
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

@if (IsValidatingEmail)
{
    <div class="text-info mb-2">
        <span class="spinner-border spinner-border-sm me-1"></span> Validating email...
    </div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">Next &raquo;</button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<PersonalInfoResult> OnNext { get; set; }

    private string? ValidationError;
    private string? EmailError;
    private bool IsValidatingEmail;

    [Inject] private Models.IApplicationService ApplicationService { get; set; } = default!;

    public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);

    private async Task HandleNext()
    {
        ValidationError = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ValidationError = "All fields are required.";
            return;
        }

        IsValidatingEmail = true;
        StateHasChanged();

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!isValid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            IsValidatingEmail = false;
        }

        await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
    }
}

@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-2">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @oninput="e => UpdateEntry(index, entry with { Company = e.Value?.ToString() ?? "" })" />
                </div>
                <div class="col-md-6 mb-2">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @oninput="e => UpdateEntry(index, entry with { Title = e.Value?.ToString() ?? "" })" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-2">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
                </div>
                <div class="col-md-4 mb-2">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" disabled="@entry.IsCurrent"
                           value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value!.ToString()!) })" />
                </div>
                <div class="col-md-4 mb-2 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" value="@entry.Description"
                          @oninput="e => UpdateEntry(index, entry with { Description = e.Value?.ToString() ?? "" })"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="HandleBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = [new()];
    [Parameter] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
    }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private async Task HandleBack() => await OnBack.InvokeAsync();

    private async Task HandleNext()
    {
        ValidationError = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ValidationError = "Company name and job title are required for each position.";
                return;
            }
        }
        await OnNext.InvokeAsync(Entries);
    }
}

