@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>
            <div class="row">
                <div class="col-md-6 mb-2">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Name"
                           @oninput="e => UpdateRef(index, reference with { Name = e.Value?.ToString() ?? "" })" />
                </div>
                <div class="col-md-6 mb-2">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Relationship"
                           @oninput="e => UpdateRef(index, reference with { Relationship = e.Value?.ToString() ?? "" })" />
                </div>
            </div>
            <div class="row">
                <div class="col-md-6 mb-2">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@reference.Email"
                           @oninput="e => UpdateRef(index, reference with { Email = e.Value?.ToString() ?? "" })" />
                </div>
                <div class="col-md-6 mb-2">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@reference.Phone"
                           @oninput="e => UpdateRef(index, reference with { Phone = e.Value?.ToString() ?? "" })" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="HandleBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = [new(), new()];
    [Parameter] public EventCallback<List<ReferenceModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    public record ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }

    private void UpdateRef(int index, ReferenceModel updated) => References[index] = updated;
    private void AddReference() { if (References.Count < 3) References.Add(new()); }
    private void RemoveReference(int index) { if (References.Count > 2) References.RemoveAt(index); }

    private async Task HandleBack() => await OnBack.InvokeAsync();

    private async Task HandleNext()
    {
        ValidationError = null;
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ValidationError = "All fields are required for each reference.";
                return;
            }
        }
        await OnNext.InvokeAsync(References);
    }
}

