@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"
              placeholder="Write your cover letter here..."></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="HandleBack">&laquo; Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private async Task HandleBack() => await OnBack.InvokeAsync();

    private async Task HandleNext()
    {
        ValidationError = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ValidationError = "A cover letter is required.";
            return;
        }
        await OnNext.InvokeAsync(CoverLetter);
    }
}

