@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application
@using sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application

<h4 class="mb-3">Review Your Application</h4>

@if (Submitted)
{
    <div class="alert alert-success text-center py-4">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>.</p>
        <p class="text-muted mt-2">Thank you for applying. We will review your application and get back to you.</p>
    </div>
}
else
{
    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(0)'>Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt>
                <dd class="col-sm-9">@FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Address</dd>
            </dl>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-2 border-bottom">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small>@r.Email &bull; @r.Phone</small>
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (SubmitError is not null)
    {
        <div class="alert alert-danger">@SubmitError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="HandleBack">&laquo; Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkHistoryStep.WorkEntryModel> WorkEntries { get; set; } = [];
    [Parameter] public List<ReferencesStep.ReferenceModel> References { get; set; } = [];
    [Parameter] public string CoverLetter { get; set; } = "";

    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool Submitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }
    [Parameter] public string? SubmitError { get; set; }

    private async Task HandleBack() => await OnBack.InvokeAsync();
    private async Task HandleSubmit() => await OnSubmit.InvokeAsync();
}

