@page "/apply"
@rendermode InteractiveServer
@namespace sv_3869f7d8164841d1815210dc969456da.Components.Pages.Application
@using sv_3869f7d8164841d1815210dc969456da.Models

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep"
                   HighestCompletedStep="@highestCompletedStep"
                   OnNavigateToStep="NavigateToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                              OnNext="HandlePersonalInfoNext" />
            break;
        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             OnNext="HandleWorkHistoryNext" OnBack="GoBack" />
            break;
        case 2:
            <ReferencesStep References="@references"
                            OnNext="HandleReferencesNext" OnBack="GoBack" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnNext="HandleCoverLetterNext" OnBack="GoBack" />
            break;
        case 4:
            <ReviewStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                        WorkEntries="@workEntries" References="@references" CoverLetter="@coverLetter"
                        OnEditStep="NavigateToStep" OnBack="GoBack" OnSubmit="HandleSubmit"
                        IsSubmitting="@isSubmitting" Submitted="@submitted"
                        ApplicationId="@applicationId" SubmitError="@submitError" />
            break;
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep;
    private int highestCompletedStep;

    // Step 1 state
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2 state
    private List<WorkHistoryStep.WorkEntryModel> workEntries = [new()];

    // Step 3 state
    private List<ReferencesStep.ReferenceModel> references = [new(), new()];

    // Step 4 state
    private string coverLetter = "";

    // Step 5 state
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;
    private string? submitError;

    private void NavigateToStep(int step)
    {
        if (step < highestCompletedStep || step == currentStep)
            currentStep = step;
    }

    private void GoBack()
    {
        if (currentStep > 0) currentStep--;
    }

    private void HandlePersonalInfoNext(PersonalInfoStep.PersonalInfoResult result)
    {
        fullName = result.FullName;
        email = result.Email;
        phone = result.Phone;
        address = result.Address;
        AdvanceStep();
    }

    private void HandleWorkHistoryNext(List<WorkHistoryStep.WorkEntryModel> entries)
    {
        workEntries = entries;
        AdvanceStep();
    }

    private void HandleReferencesNext(List<ReferencesStep.ReferenceModel> refs)
    {
        references = refs;
        AdvanceStep();
    }

    private void HandleCoverLetterNext(string letter)
    {
        coverLetter = letter;
        AdvanceStep();
    }

    private void AdvanceStep()
    {
        currentStep++;
        if (currentStep > highestCompletedStep)
            highestCompletedStep = currentStep;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;
        StateHasChanged();

        try
        {
            var workHistory = new WorkHistory(
                workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate, e.EndDate, e.Description
                )).ToList()
            );

            var refList = references.Select(r => new Reference(
                r.Name, r.Relationship, r.Email, r.Phone
            )).ToList();

            var personal = new PersonalInfo(fullName, email, phone, address);
            var application = new JobApplication(personal, workHistory, refList, coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            submitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

