@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = [new()];
    [Parameter] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    public record WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private static string Str(object? value) => value?.ToString() ?? "";
    private static string FormatEndDate(WorkEntryModel entry) => entry.EndDate?.ToString("yyyy-MM-dd") ?? "";

    private void SetCompany(int i, ChangeEventArgs e) => Entries[i] = Entries[i] with { Company = Str(e.Value) };
    private void SetTitle(int i, ChangeEventArgs e) => Entries[i] = Entries[i] with { Title = Str(e.Value) };
    private void SetDescription(int i, ChangeEventArgs e) => Entries[i] = Entries[i] with { Description = Str(e.Value) };

    private void SetStartDate(int i, ChangeEventArgs e)
    {
        var val = Str(e.Value);
        if (DateTime.TryParse(val, out var date))
            Entries[i] = Entries[i] with { StartDate = date };
    }

    private void SetEndDate(int i, ChangeEventArgs e)
    {
        var val = Str(e.Value);
        Entries[i] = Entries[i] with { EndDate = string.IsNullOrEmpty(val) ? null : DateTime.Parse(val) };
    }

    private void SetIsCurrent(int i, ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        Entries[i] = Entries[i] with { IsCurrent = isCurrent, EndDate = isCurrent ? null : Entries[i].EndDate };
    }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private async Task HandleBack() => await OnBack.InvokeAsync();

    private async Task HandleNext()
    {
        ValidationError = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ValidationError = "Company name and job title are required for each position.";
                return;
            }
        }
        await OnNext.InvokeAsync(Entries);
    }
}

